test('seed-dsl compile writes a deterministic command bundle', async () => {
  const dir = await fs.mkdtemp(path.join(os.tmpdir(), 'bim-ai-seed-dsl-'));
  const outPath = path.join(dir, 'bundle.json');
  const recipePath = path.resolve(
